const item1 = $input.all()[0];
const item2 = $input.all()[1];

// Deep clone to prevent "Cannot assign to read-only property" proxy errors downstream
const raw1 = item1 ? JSON.parse(JSON.stringify(item1.json)) : {};
const raw2 = item2 ? JSON.parse(JSON.stringify(item2.json)) : {};

let extracted = raw1.extracted_papers || raw1;
let rawAnalysis = raw2.analysis || raw2;

// Handle Double-Stringified JSON gracefully
let analysis = rawAnalysis;
if (typeof rawAnalysis === 'string') {
  try {
    analysis = JSON.parse(rawAnalysis);
  } catch(e) {
    console.error("Failed to parse double-stringified analysis:", e);
  }
}
if (!analysis || typeof analysis !== 'object') analysis = {};

const safeArray = (arr) => Array.isArray(arr) ? arr : [];

return [{
  json: {
    trigger_source: "INITIAL",
    paper_count: analysis.analysis_metadata?.total_papers || Object.keys(extracted).length,
    year_range: analysis.analysis_metadata?.year_range || "Unknown",
    paper_reference_table: JSON.stringify(extracted),
    themes_summary: JSON.stringify(safeArray(analysis.themes)),
    methodology_matrix: JSON.stringify(analysis.methodology_comparison || {}),
    research_gaps: JSON.stringify(safeArray(analysis.research_gaps)),
    cross_cutting_findings: JSON.stringify(safeArray(analysis.cross_cutting_findings)),
    full_paper_data: JSON.stringify(extracted)
  }
}];

let draft = $input.first().json.text || $input.first().json.output || $input.first().json;

function parseTables(text) {
    const tableRegex = /(?:^|\n)(\|[^\n]+\|(?:\n\|[^\n]+\|)+)/g;
    return text.replace(tableRegex, (match, tableBlock) => {
        let rows = tableBlock.trim().split('\n');
        let html = '<table style="border-collapse: collapse; width: 100%; margin: 20px 0; font-size: 14px; text-align: left;">\n';
        for (let i = 0; i < rows.length; i++) {
            let row = rows[i].trim();
            // check if it's the separator row e.g. |---|---|
            if (row.replace(/[\s|:\-]/g, '').length === 0) continue; 

            let cells = row.split('|');
            cells.shift(); // remove empty before first |
            cells.pop();   // remove empty after last |

            html += '  <tr>\n';
            for (let cell of cells) {
                let tag = i === 0 ? 'th' : 'td';
                let style = i === 0 
                  ? ' style="background-color: #f4f4f4; padding: 12px; border: 1px solid #ddd; border-bottom: 2px solid #bbb;"' 
                  : ' style="padding: 12px; border: 1px solid #ddd;"';
                html += `    <${tag}${style}>${cell.trim()}</${tag}>\n`;
            }
            html += '  </tr>\n';
        }
        html += '</table>\n';
        return '\n\n' + html + '\n\n';
    });
}

draft = parseTables(draft);

return [{
  json: { text: draft },
  binary: {
    data: {
      data: Buffer.from(draft).toString('base64'),
      mimeType: 'text/plain',
      fileName: 'temp_draft.txt'
    }
  }
}];

