const htmlStyled = `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<title>Literature Review</title>
<style>
  body {
    max-width: 900px;
    margin: 40px auto; 
    padding: 0 20px;
    background-color: #fff;
    font-family: "Times New Roman", Times, serif;
    line-height: 1.6;
  }
  h1, h2, h3 { text-align: center; font-family: Arial, Helvetica, sans-serif; }
  p { text-align: justify; }
</style>
</head>
<body>
${htmlRaw}
</body>
</html>`;

return [{
  json: { success: true },
  binary: {
    html_data: {
      data: Buffer.from(htmlStyled).toString('base64'),
      mimeType: 'text/html',
      fileName: 'literature_review.html'
    }
  }
}];

const draftData = await this.helpers.getBinaryDataBuffer(0, 'data');
const currentDraft = draftData.toString('utf8');

const webhookItems = $('Webhook (Revision)').all();
const webhookBody = webhookItems[0].json.body || webhookItems[0].json;

return [{
  json: {
    trigger_source: 'REVISION',
    current_draft: currentDraft,
    fabricated_claims: typeof webhookBody.fabricated_claims === 'string' ? webhookBody.fabricated_claims : JSON.stringify(webhookBody.fabricated_claims || [], null, 2),
    feedback_summary: webhookBody.feedback_summary || 'Revision requested.',
    source_data: webhookBody.source_data || 'Source papers not provided.'
  }
}];

const data = $input.first().json;
const mode = data.trigger_source || 'INITIAL';

let systemPrompt = '';
let userPrompt = '';

if (mode === 'INITIAL') {
  systemPrompt = `You are the Review Writer Agent. Your SOLE job is to write an IEEE-format academic literature review from the provided data.

## STRICT RULES
1. WRITE ONLY from provided data. NO external knowledge.
2. MANDATORY CITATIONS: Every factual claim MUST have [P<id>] inline citation.
3. IEEE FORMAT with these exact sections: I. ABSTRACT, II. INTRODUCTION, III. METHODOLOGY OF REVIEW, IV. THEMATIC ANALYSIS, V. COMPARATIVE ANALYSIS, VI. DISCUSSION, VII. CONCLUSION, VIII. REFERENCES
4. Academic, formal tone.
5. NEVER add information not in the provided data.`;
  userPrompt = `Write a complete IEEE-format literature review based on the following data from ${data.paper_count} academic papers spanning ${data.year_range}.

=== PAPER REFERENCE LIST ===
${data.paper_reference_table}

=== IDENTIFIED THEMES ===
${data.themes_summary}

=== METHODOLOGY COMPARISON ===
${data.methodology_matrix}

=== RESEARCH GAPS ===
${data.research_gaps}

=== CROSS-CUTTING FINDINGS ===
${data.cross_cutting_findings}

=== FULL PAPER DATA ===
${data.full_paper_data}

Write the COMPLETE literature review now. Every claim must have [P<id>] citations.`;
} else {
  systemPrompt = `You are the Review Revision Agent. A Fact-Checker has identified factual errors in your previous draft.

## STRICT RULES
1. CAREFULLY fix ONLY the fabricated claims mentioned.
2. KEEP the rest of the text and structure exactly as it was.
3. Remove false claims completely OR adjust them to match facts if provided.
4. Base your corrections on the ORIGINAL SOURCE PAPERS provided.
5. Maintain IEEE format and all sections.`;
  userPrompt = `=== FACT-CHECKER FEEDBACK ===
${data.feedback_summary}

=== FABRICATED CLAIMS TO FIX ===
${data.fabricated_claims}

=== ORIGINAL SOURCE PAPERS (GROUND TRUTH) ===
${data.source_data}

=== PREVIOUS DRAFT ===
${data.current_draft}

Based on the feedback and ground truth above, REVISE the draft. Return the FULL updated draft but ONLY change the parts related to the fabricated claims. DO NOT output markdown code blocks if possible, just the raw text.`;
}

return [{ json: { ...data, dynamic_system_prompt: systemPrompt, dynamic_user_prompt: userPrompt } }];
